sql:
SELECT name 
FROM projects 
WHERE pledged > (SELECT AVG(pledge_amount) FROM backers WHERE pledge_amount > 50000);

SELECT AVG(number_of_backers) AS average_number_of_backers
FROM (
  SELECT project_id, COUNT(*) AS number_of_backers
  FROM backers
  GROUP BY project_id
) AS project_backer_counts;

SELECT project_id, average_donation
FROM average_donations
WHERE average_donation = (
    SELECT MAX(average_donation)
    FROM average_donations
);

SELECT COUNT(backer_id) 
FROM backers 
WHERE project_id = 5;

SELECT name, email 
FROM backers 
WHERE pledge_amount > (SELECT AVG(pledge_amount) FROM backers);

SELECT project_id, MAX(pledge_amount) AS highest_pledge
FROM backers
GROUP BY project_id;

SELECT name, pledge_amount
FROM backers
WHERE pledge_amount > (
  SELECT AVG(pledge_amount)
  FROM backers
);

external_knowledge:
- "riding the wave of popular support" refers to projects with a pledged amount exceeding the average;
- "above the ocean's tide" implies that the pledged amount is higher than the average pledged amount across all projects;
- "current with regards to the average donation per project" signifies the average donation amount for the project;
- "rivers of contributions by their flow" represents projects sorted by their pledged amounts in descending order.
